      quantidadeExamesInput2:
        examesInput2.length,

      examesInput1,
      examesInput2,

      examesFaltandoNoInput2:
        examesFaltando,

      examesExtrasNoInput2:
        examesExtras,

      erro: !matchExames,

      mensagem:
        matchExames
          ? "Paciente e exames estão exatamente iguais"
          : matchPaciente
            ? "Paciente encontrado, mas há divergência entre os exames"
            : "Paciente não encontrado com nome completo igual nem com 3 palavras iguais"
    }
  });
}

return resultado;

