const items = $input.all();

const resultado = [];

// pega data atual (zera hora)
const hoje = new Date();
hoje.setHours(0, 0, 0, 0);

function parseDataBR(dataStr) {
  if (!dataStr) return null;

  const partes = dataStr.split("/");
  if (partes.length !== 3) return null;

  const [dia, mes, ano] = partes.map(Number);

  return new Date(ano, mes - 1, dia);
}

for (const item of items) {
  const j = item.json;

  // -------------------------
  // NORMALIZAÇÃO
  // -------------------------
  const categoria = String(j["CATEGORIA"] || "").trim().toUpperCase();

  const valorRaw = String(j["VALOR"] || "").trim();

  const valorNumero = parseFloat(
    valorRaw.replace(".", "").replace(",", ".")
  );

  const valorEhZeroOuVazio =
    valorRaw === "" ||
    valorRaw === "." ||
    valorNumero === 0 ||
    isNaN(valorNumero);

  // -------------------------
  // DATA
  // -------------------------
  const dataItem = parseDataBR(j["DATA"]);

  const dataValida =
    dataItem && dataItem < hoje; // 👈 AQUI está a regra

  // -------------------------
  // CONDIÇÃO FINAL
  // -------------------------
  const condicaoCategoria =
    categoria === "(+)COMPUTADOR DO POSTO";

  if (condicaoCategoria && valorEhZeroOuVazio && dataValida) {

    const chaveResumo = `${j["DATA"] || ""} | ${j["POSTO"] || ""} | ${j["CATEGORIA"] || ""}`;

    resultado.push({
      json: {
        ...j,
        chaveResumo,
        _match: true
      }
    });
  }
}

return resultado;

let ocr = [];
let planilha = [];

// tenta pegar OCR
try {
  ocr = $("Code in JavaScript3").all().map(i => i.json);
} catch (e) {
  ocr = [];
}

// tenta pegar planilha
try {
  planilha = $("Code in JavaScript4").all().map(i => i.json);
} catch (e) {
  planilha = [];
}

const resultado = [];

function norm(v) {
  return String(v ?? "")
    .replace(/\s+/g, " ")
    .trim()
    .toUpperCase();
}

// proteção extra: só roda se ambos tiverem dados
if (ocr.length && planilha.length) {
  for (const itemOcr of ocr) {
    const chaveMatch = norm(itemOcr.chaveMatch);
    if (!chaveMatch) continue;

    for (const itemPlanilha of planilha) {
      const chaveResumo = norm(itemPlanilha.chaveResumo);
      if (!chaveResumo) continue;

      if (chaveMatch === chaveResumo) {
        resultado.push({
          json: {
            ...itemOcr,
            ...itemPlanilha,
            match: true
          }
        });
      }
    }
  }
}

// sempre retorna array válido
return resultado;
